  if (!req.file) return res.send('No image uploaded');
  const filename = Date.now();
  const ext = '.jpg';

  await sharp(req.file.buffer).resize(100, 100).toFile(`uploads/small/${filename}${ext}`);
  await sharp(req.file.buffer).resize(300, 300).toFile(`uploads/medium/${filename}${ext}`);
  await sharp(req.file.buffer).resize(800, 800).toFile(`uploads/large/${filename}${ext}`);

  res.send(`<h2>Image saved in 3 sizes: small(100x100), medium(300x300), large(800x800)</h2>`);
