const express = require('express');
const nodemailer = require('nodemailer');
const path = require('path');
const app = express();
app.use(express.urlencoded({ extended: true }));
app.use(express.static(__dirname));

const transporter = nodemailer.createTransport({
  service: 'gmail',
  auth: { user: 'lju@gmail.com', pass: 'app_password' }
});

app.get('/', (req, res) => {
  res.sendFile(path.join(__dirname, 'mail.html'));
});

app.post('/sendmail', (req, res) => {
  const { email } = req.body;
  const mailOptions = {
    from: 'lju@gmail.com',
    to: email,
    subject: 'Exam Timetable',
    html: `
      <h3>L J University</h3>
      <table border='1' cellpadding='8'>
        <tr><th>Date</th><th>Exam Name</th></tr>
        <tr><td>21/05/25</td><td>FSD-2</td></tr>
      </table>
    `
  };
  transporter.sendMail(mailOptions, (err, info) => {
    if (err) return res.send('Error: ' + err.message);
    res.send(`Email sent to ${email} successfully!`);
  });
});

app.listen(3000, () => console.log('Server on port 3000'));

