import React, { useState } from 'react';

function App() {
  const [heading, setHeading] = useState('LJ University');
  const [color, setColor] = useState('red');
  const [visible, setVisible] = useState(true);
  const [btnText, setBtnText] = useState('Hide');

  const changeText = () => {
    setHeading(prev => prev === 'LJ University' ? 'Welcome students' : 'LJ University');
  };

  const changeColor = () => {
    setColor(prev => prev === 'red' ? 'blue' : 'red');
  };

  const toggleVisibility = () => {
    setVisible(prev => !prev);
    setBtnText(prev => prev === 'Hide' ? 'Show' : 'Hide');
  };

  return (
    <div>
      <h1 style={{ color: color }}>{heading}</h1>
      {visible && <h2>React Js Hooks</h2>}
      <button onClick={changeText}>Change Text</button>
      <button onDoubleClick={changeColor}>Change Color</button>
      <button onClick={toggleVisibility}>{btnText}</button>
    </div>
  );
}
export default App;

