import React, { useState, useEffect } from 'react';

function App() {
  const [num1, setNum1] = useState('');
  const [num2, setNum2] = useState('');
  const [result, setResult] = useState(null);
  const [addClicked, setAddClicked] = useState(0);

  useEffect(() => {
    if (addClicked > 0) {
      alert('Addition performed!');
    }
  }, [addClicked]);

  const add = () => {
    setResult(parseFloat(num1) + parseFloat(num2));
    setAddClicked(prev => prev + 1);
  };

  const subtract = () => {
    setResult(parseFloat(num1) - parseFloat(num2));
  };

  return (
    <div>
      <input type='number' placeholder='Number 1' value={num1} onChange={e => setNum1(e.target.value)} /><br />
      <input type='number' placeholder='Number 2' value={num2} onChange={e => setNum2(e.target.value)} /><br />
      <button onClick={add}>Add</button>
      <button onClick={subtract}>Subtract</button>
      {result !== null && <h2>Result: {result}</h2>}
    </div>
  );
}
export default App;

