import React, { useState, useEffect, useRef } from 'react';

function App() {
  const [count, setCount] = useState(0);
  const [running, setRunning] = useState(false);
  const intervalRef = useRef(null);

  useEffect(() => {
    if (running) {
      intervalRef.current = setInterval(() => {
        setCount(prev => prev + 1);
      }, 1000);
    } else {
      clearInterval(intervalRef.current);
    }
    return () => clearInterval(intervalRef.current);
  }, [running]);

  return (
    <div>
      <h1>Counter: {count}</h1>
      <button onClick={() => setRunning(true)}>Start</button>
      <button onClick={() => setRunning(false)}>Stop</button>
    </div>
  );
}
export default App;

import React, { useReducer } from 'react';

function reducer(state, action) {
  switch (action.type) {
    case 'add': return state + 1;
    case 'remove': return state > 0 ? state - 1 : 0;
    default: return state;
  }
}

function App() {
  const [quantity, dispatch] = useReducer(reducer, 0);

  return (
    <div>
      <h2>Product Quantity: {quantity}</h2>
      <button onClick={() => dispatch({ type: 'add' })}>Add Item</button>
      <button onClick={() => dispatch({ type: 'remove' })}>Remove Item</button>
