import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [form, setForm] = useState({ name: '', empId: '', salary: '', department: '' });
  const [employees, setEmployees] = useState([]);

  useEffect(() => { fetchEmployees(); }, []);

  const fetchEmployees = async () => {
    const res = await axios.get('http://localhost:5000/api/employees');
    setEmployees(res.data);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:5000/api/employees', form);
    fetchEmployees();
    setForm({ name: '', empId: '', salary: '', department: '' });
  };

  return (
    <div>
      <form onSubmit={handleSubmit}>
        <input placeholder="Name" value={form.name} onChange={e => setForm({...form, name: e.target.value})} />
        <input placeholder="ID" value={form.empId} onChange={e => setForm({...form, empId: e.target.value})} />
        <input placeholder="Salary" type="number" value={form.salary} onChange={e => setForm({...form, salary: e.target.value})} />
        <input placeholder="Department" value={form.department} onChange={e => setForm({...form, department: e.target.value})} />
        <button type="submit">Submit</button>
      </form>
      <table border="1">
        <thead><tr><th>Name</th><th>ID</th><th>Salary</th><th>Department</th></tr></thead>
        <tbody>
          {employees.map(emp => (
            <tr key={emp._id}><td>{emp.name}</td><td>{emp.empId}</td><td>{emp.salary}</td><td>{emp.department}</td></tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
export default App;

